#include <XSegment_lib.h>

XSeg_MAX7219 display(2, 3, 4, 4);

void setup() {
  Serial.begin(115200);
  display.begin();
  display.setBrightness(7);

  Serial.println("=== MAX7219 Demo ===");
}

void loop() {
  static int32_t counter = 0;

  // 4-digit display
  display.show(counter);
  Serial.print("Display: "); Serial.println(counter);
  counter += 100;
  delay(300);

  // String
  display.show("TEST");
  Serial.println("Display: TEST");
  delay(500);

  // Negative
  display.show(-1234);
  Serial.println("Display: -1234");
  delay(500);

  // Float
  display.show(12.34f, 2);
  Serial.println("Display: 12.34");
  delay(500);

  // Clear
  display.clear();
  Serial.println("Display: (clear)");
  delay(200);
}
